// ─── Export Configuration ──────────────────────────────────────────────

export interface ExportConfiguration {
  resolution: ResolutionPreset;
  format: FormatOption;
  quality: QualityPreset;
  codec: VideoCodec;
  fps: number;
  customBitrateKbps: number | null;
  includeAudio: boolean;
}

export interface FFmpegSettings {
  width: number;
  height: number;
  videoCodec: string;
  audioCodec: string;
  crf: number;
  preset: string;
  videoBitrateKbps: number;
  audioBitrateKbps: number;
  fps: number;
  format: string;
  pixelFormat: string;
  additionalFlags: string[];
}

// ─── Pure Functions ────────────────────────────────────────────────────

/**
 * Calculate recommended video bitrate based on resolution, quality, and format.
 */
export function calculateBitrate(
  width: number,
  height: number,
  quality: QualityPreset,
  fps: number = 30,
): number {
  // Base bitrate calculation: pixels * factor
  const pixels = width * height;
  const baseBitratePerPixel = 0.004; // kbps per pixel for 30fps medium quality
  const fpsMultiplier = fps / 30;

  const baseBitrate = pixels * baseBitratePerPixel * fpsMultiplier;
  const adjustedBitrate = baseBitrate * quality.bitrateMultiplier;

  // Clamp to reasonable range
  return Math.round(Math.max(500, Math.min(adjustedBitrate, 50000)));
}

/**
 * Estimate file size in bytes based on export settings and duration.
 */
export function estimateFileSize(
  durationSeconds: number,
  videoBitrateKbps: number,
  audioBitrateKbps: number,
  includeAudio: boolean = true,
): number {
  if (durationSeconds <= 0) return 0;

  // Convert kbps to bytes/sec: kbps * 1000 / 8
  const videoBytesPerSecond = (videoBitrateKbps * 1000) / 8;
  const audioBytesPerSecond = includeAudio ? (audioBitrateKbps * 1000) / 8 : 0;

  const totalBytesPerSecond = videoBytesPerSecond + audioBytesPerSecond;
  const rawSize = totalBytesPerSecond * durationSeconds;

  // Add ~5% overhead for container format
  return Math.round(rawSize * 1.05);
}

/**
 * Format file size to human-readable string.
 */
export function formatFileSize(bytes: number): string {
  if (bytes <= 0) return '0 B';

  const units = ['B', 'KB', 'MB', 'GB'] as const;
  let unitIndex = 0;
  let size = bytes;

  while (size >= 1024 && unitIndex < units.length - 1) {
    size /= 1024;
    unitIndex++;
  }

  return `${size.toFixed(unitIndex === 0 ? 0 : 1)} ${units[unitIndex]}`;
}

/**
 * Get resolution preset by ID.
 */
export function getResolutionPreset(id: string): ResolutionPreset | undefined {
  return RESOLUTION_PRESETS.find(r => r.id === id);
}

/**
 * Get platform preset by ID.
 */
export function getPlatformPreset(id: string): PlatformPreset | undefined {
  return PLATFORM_PRESETS.find(p => p.id === id);
}

/**
 * Get format option by ID.
 */
export function getFormatOption(id: ExportFormat): FormatOption | undefined {
  return FORMAT_OPTIONS.find(f => f.id === id);
}

/**
 * Get quality preset by ID.
 */
export function getQualityPreset(id: QualityLevel): QualityPreset | undefined {
  return QUALITY_PRESETS.find(q => q.id === id);
}

/**
 * Check if a resolution is allowed for a given user plan.
 */
export function isResolutionAllowed(
  resolution: ResolutionPreset,
  plan: UserPlan,
): boolean {
  const limits = PLAN_LIMITS[plan];
  return resolution.width <= limits.maxWidth && resolution.height <= limits.maxHeight;
}

/**
 * Check if a format is allowed for a given user plan.
 */
export function isFormatAllowed(format: ExportFormat, plan: UserPlan): boolean {
  const limits = PLAN_LIMITS[plan];
  return (limits.allowedFormats as readonly string[]).includes(format);
}

/**
 * Get all available resolutions for a user plan.
 */
export function getAvailableResolutions(plan: UserPlan): ResolutionPreset[] {
  return RESOLUTION_PRESETS.filter(r => isResolutionAllowed(r, plan));
}

/**
 * Get all available platform presets for a user plan.
 */
export function getAvailablePlatformPresets(plan: UserPlan): PlatformPreset[] {
  const limits = PLAN_LIMITS[plan];
  return PLATFORM_PRESETS.filter(
    p => p.width <= limits.maxWidth && p.height <= limits.maxHeight,
  );
}

/**
 * Build FFmpeg settings from an ExportConfiguration.
 */
export function buildFFmpegSettings(config: ExportConfiguration): FFmpegSettings {
  const videoBitrate =
    config.customBitrateKbps ??
    calculateBitrate(
      config.resolution.width,
      config.resolution.height,
      config.quality,
      config.fps,
    );

  const codecMap: Record<VideoCodec, string> = {
    h264: 'libx264',
    h265: 'libx265',
    vp9: 'libvpx-vp9',
  };

  const audioCodecMap: Record<AudioCodec, string> = {
    aac: 'aac',
    opus: 'libopus',
    mp3: 'libmp3lame',
  };

  const additionalFlags: string[] = [];

  // H.265 needs specific flags
  if (config.codec === 'h265') {
    additionalFlags.push('-tag:v', 'hvc1');
  }

  // VP9 two-pass for better quality
  if (config.codec === 'vp9' && config.quality.id !== 'low') {
    additionalFlags.push('-row-mt', '1');
  }

  // 4K needs larger buffers
  if (config.resolution.width >= 3840) {
    additionalFlags.push('-bufsize', `${videoBitrate * 2}k`);
    additionalFlags.push('-maxrate', `${Math.round(videoBitrate * 1.5)}k`);
  }

  return {
    width: config.resolution.width,
    height: config.resolution.height,
    videoCodec: codecMap[config.codec],
    audioCodec: audioCodecMap[config.format.audioCodec],
    crf: config.quality.crf,
    preset: config.quality.ffmpegPreset,
    videoBitrateKbps: videoBitrate,
    audioBitrateKbps: config.quality.audioBitrateKbps,
    fps: config.fps,
    format: config.format.id,
    pixelFormat: 'yuv420p',
    additionalFlags,
  };
}

/**
 * Build ExportConfiguration from a platform preset.
 */
export function buildConfigFromPlatform(platformId: string): ExportConfiguration | null {
  const platform = getPlatformPreset(platformId);
  if (!platform) return null;

  // Find matching resolution
  const resolution = RESOLUTION_PRESETS.find(
    r => r.width === platform.width && r.height === platform.height,
  );

  // Find format
  const format = getFormatOption(platform.format);

  // Determine quality from bitrate
  const quality = inferQualityFromBitrate(
    platform.recommendedBitrateKbps,
    platform.width,
    platform.height,
  );

  if (!format || !quality) return null;

  return {
    resolution: resolution ?? {
      id: `custom-${platform.width}x${platform.height}`,
      label: `${platform.width}x${platform.height}`,
      width: platform.width,
      height: platform.height,
      aspectRatio: platform.aspectRatio,
      description: platform.description,
      requiresPremium: platform.requiresPremium,
    },
    format,
    quality,
    codec: platform.codec,
    fps: platform.fps,
    customBitrateKbps: platform.recommendedBitrateKbps,
    includeAudio: true,
  };
}

/**
 * Infer quality level from bitrate relative to resolution.
 */
export function inferQualityFromBitrate(
  bitrateKbps: number,
  width: number,
  height: number,
): QualityPreset {
  const pixels = width * height;
  const baseBitrate = pixels * 0.004;

  const ratio = bitrateKbps / baseBitrate;

  if (ratio >= 1.75) return QUALITY_PRESETS[3]; // ultra
  if (ratio >= 1.25) return QUALITY_PRESETS[2]; // high
  if (ratio >= 0.75) return QUALITY_PRESETS[1]; // medium
  return QUALITY_PRESETS[0]; // low
}

/**
 * Validate export configuration against plan limits.
 */
export interface ExportValidationResult {
  valid: boolean;
  errors: string[];
  warnings: string[];
}

export function validateExportConfig(
  config: ExportConfiguration,
  plan: UserPlan,
  durationSeconds: number,
): ExportValidationResult {
  const limits = PLAN_LIMITS[plan];
  const errors: string[] = [];
  const warnings: string[] = [];

  // Check resolution
  if (!isResolutionAllowed(config.resolution, plan)) {
    errors.push(
      `Resolução ${config.resolution.label} requer plano ${config.resolution.requiresPremium ? 'Pro' : 'superior'}. ` +
        `Seu plano permite até ${limits.maxResolution}.`,
    );
  }

  // Check format
  if (!isFormatAllowed(config.format.id, plan)) {
    errors.push(
      `Formato ${config.format.label} não disponível no plano ${plan}. ` +
        `Formatos disponíveis: ${limits.allowedFormats.join(', ').toUpperCase()}.`,
    );
  }

  // Check duration
  if (durationSeconds > limits.maxDurationSeconds) {
    errors.push(
      `Duração do vídeo (${Math.ceil(durationSeconds)}s) excede o limite do plano ` +
        `(${limits.maxDurationSeconds}s). Encurte o vídeo ou faça upgrade do plano.`,
    );
  }

  // Check watermark
  if (limits.includesWatermark) {
    warnings.push(
      'Seu plano inclui marca d\'água no vídeo. Faça upgrade para removê-la.',
    );
  }

  // Warn about large file sizes
  const videoBitrate =
    config.customBitrateKbps ??
    calculateBitrate(
      config.resolution.width,
      config.resolution.height,
      config.quality,
      config.fps,
    );
  const estimatedBytes = estimateFileSize(
    durationSeconds,
    videoBitrate,
    config.quality.audioBitrateKbps,
    config.includeAudio,
  );
  const estimatedMB = estimatedBytes / (1024 * 1024);

  if (estimatedMB > 500) {
    warnings.push(
      `Arquivo estimado em ${formatFileSize(estimatedBytes)}. Exportação pode demorar.`,
    );
  }

  if (estimatedMB > 2048) {
    warnings.push('Arquivo maior que 2 GB pode causar problemas em algumas plataformas.');
  }

  return {
    valid: errors.length === 0,
    errors,
    warnings,
  };
}

/**
 * Get default export configuration for a user plan.
 */
export function getDefaultConfig(plan: UserPlan): ExportConfiguration {
  const limits = PLAN_LIMITS[plan];

  // Pick best non-premium resolution allowed (default to 1080p or best available)
  const preferredResolution = RESOLUTION_PRESETS.find(r => r.id === '1080p');
  const resolution =
    preferredResolution && preferredResolution.width <= limits.maxWidth
      ? preferredResolution
      : RESOLUTION_PRESETS.filter(r => r.width <= limits.maxWidth && !r.requiresPremium).pop() ??
        RESOLUTION_PRESETS[0];

  // Pick mp4 (universal)
  const format = FORMAT_OPTIONS[0]; // mp4

  // Pick medium quality
  const quality = QUALITY_PRESETS[1]; // medium

  return {
    resolution,
    format,
    quality,
    codec: format.defaultCodec,
    fps: 30,
    customBitrateKbps: null,
    includeAudio: true,
  };
}

/**
 * Estimate export duration (rough, based on duration and resolution).
 * Returns estimated seconds to process.
 */
export function estimateExportDuration(
  durationSeconds: number,
  width: number,
  height: number,
  qualityLevel: QualityLevel,
): number {
  // Base: realtime at 1080p medium
  const pixels = width * height;
  const basePixels = 1920 * 1080;
  const resolutionFactor = pixels / basePixels;

  const qualityFactors: Record<QualityLevel, number> = {
    low: 0.5,
    medium: 1.0,
    high: 2.0,
    ultra: 4.0,
  };

  const qualityFactor = qualityFactors[qualityLevel];

  // Estimate: duration * resolution_factor * quality_factor * overhead
  return Math.round(durationSeconds * resolutionFactor * qualityFactor * 1.2);
}

/**
 * Format duration to human-readable estimate.
 */
export function formatEstimatedDuration(seconds: number): string {
  if (seconds <= 0) return '< 1 segundo';
  if (seconds < 60) return `~${seconds} segundo${seconds !== 1 ? 's' : ''}`;

  const minutes = Math.ceil(seconds / 60);
  if (minutes < 60) return `~${minutes} minuto${minutes !== 1 ? 's' : ''}`;

  const hours = Math.floor(minutes / 60);
  const remainingMinutes = minutes % 60;
  if (remainingMinutes === 0) return `~${hours} hora${hours !== 1 ? 's' : ''}`;
  return `~${hours}h ${remainingMinutes}min`;
}
